1	export type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Damage = { itemType: string; amount: number };
14	export type Incident = { cause: string; damages: Damage[] };
15	export type ClaimStep = {
16	  op: "claim";
17	  policy: number;
18	  incident: Incident;
19	};
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export type Scenario = {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	};
27	
28	export type QuoteResult = { premium: number };
29	export type ClaimResult = { payout: number; remainingCap: number };
30	export type StepResult = QuoteResult | ClaimResult;
31	export type ScenarioResult = { results: StepResult[] };
32	
33	const PROCESSING_FEE = 5;
34	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
35	const DEDUCTIBLE = 100;
36	const CAP_MULTIPLIER = 2;
37	
38	const INSURANCE_VALUES: Record<string, number> = {
39	  sword: 1000,
40	  amulet: 600,
41	  staff: 800,
42	  potion: 400,
43	  rune: 250,
44	  moonstone: 250,
45	};
46	
47	const BASE_PREMIUMS: Record<string, number> = {
48	  sword: 100,
49	  amulet: 60,
50	  staff: 80,
51	  potion: 40,
52	  rune: 25,
53	  moonstone: 25,
54	};
55	
56	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
57	const BLOCK_SIZE = 3;
58	const BLOCK_BASE_PREMIUM = 60;
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
62	const LOYALTY_THRESHOLD_YEARS = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
65	
66	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
67	
68	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
69	
70	const componentGroupBasePremium = (type: string, count: number): number =>
71	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
72	
73	const sumItemBasePremiums = (items: Item[]): number => {
74	  const componentCounts = new Map<string, number>();
75	  let total = 0;
76	  for (const item of items) {
77	    if (isComponent(item)) {
78	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
79	    } else {
80	      total += itemBasePremium(item);
81	    }
82	  }
83	  for (const [type, count] of componentCounts) {
84	    total += componentGroupBasePremium(type, count);
85	  }
86	  return total;
87	};
88	
89	const isHighlyEnchanted = (item: Item): boolean =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
91	
92	const itemSurcharges = (item: Item): number => {
93	  const base = itemBasePremium(item);
94	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
95	  const enchantmentSurcharge = isHighlyEnchanted(item)
96	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
97	    : 0;
98	  return curseSurcharge + enchantmentSurcharge;
99	};
100	
101	const sumItemSurcharges = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
103	
104	const firstInsuranceSurchargeOn = (baseTotal: number): number =>
105	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
106	
107	export type Customer = { yearsWithMHPCO: number };
108	
109	const isLoyal = (customer: Customer): boolean =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
111	
112	const loyaltyDiscountOn = (baseTotal: number, customer: Customer): number =>
113	  isLoyal(customer) ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
114	
115	const quoteStep = (
116	  step: QuoteStep,
117	  customer: Customer,
118	  isFollowUp: boolean,
119	): QuoteResult => {
120	  const baseTotal = sumItemBasePremiums(step.items);
121	  const itemSurchargesTotal = sumItemSurcharges(step.items);
122	  const firstInsurance = firstInsuranceSurchargeOn(baseTotal);
123	  const loyaltyDiscount = loyaltyDiscountOn(baseTotal, customer);
124	  const followUpDiscount = isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
125	  const premium = Math.ceil(
126	    baseTotal +
127	      itemSurchargesTotal +
128	      firstInsurance -
129	      loyaltyDiscount -
130	      followUpDiscount +
131	      PROCESSING_FEE,
132	  );
133	  return { premium };
134	};
135	
136	type Policy = { items: Item[]; remainingCap: number };
137	
138	const policyInsuranceSum = (items: Item[]): number =>
139	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
140	
141	const createPolicy = (items: Item[]): Policy => ({
142	  items,
143	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
144	});
145	
146	const SEVERE_ENCHANTMENT_THRESHOLD = 8;
147	const SEVERE_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
148	
149	const reimbursableAmount = (damage: Damage, item: Item): number => {
150	  const enchantment = item.enchantment ?? 0;
151	  if (enchantment >= SEVERE_ENCHANTMENT_THRESHOLD) {
152	    return damage.amount * SEVERE_ENCHANTMENT_REIMBURSEMENT_RATE;
153	  }
154	  return damage.amount;
155	};
156	
157	const damagePayout = (damage: Damage, item: Item): number =>
158	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
159	
160	const findCoveredItem = (items: Item[], itemType: string): Item =>
161	  items.find((item) => item.type === itemType)!;
162	
163	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
164	  damages.reduce(
165	    (sum, damage) => sum + damagePayout(damage, findCoveredItem(items, damage.itemType)),
166	    0,
167	  );
168	
169	const countsByType = <T extends { type?: string; itemType?: string }>(
170	  entries: T[],
171	  keyFn: (e: T) => string,
172	): Map<string, number> => {
173	  const counts = new Map<string, number>();
174	  for (const entry of entries) {
175	    const k = keyFn(entry);
176	    counts.set(k, (counts.get(k) ?? 0) + 1);
177	  }
178	  return counts;
179	};
180	
181	const validateClaimCoverage = (damages: Damage[], items: Item[]): void => {
182	  const itemCounts = countsByType(items, (i) => i.type);
183	  const damageCounts = countsByType(damages, (d) => d.itemType);
184	  for (const [type, count] of damageCounts) {
185	    if (count > (itemCounts.get(type) ?? 0)) {
186	      throw new Error(
187	        `claim has ${count} damage(s) of type "${type}" but policy only covers ${itemCounts.get(type) ?? 0}`,
188	      );
189	    }
190	  }
191	};
192	
193	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
194	  validateClaimCoverage(step.incident.damages, policy.items);
195	  const payout = sumDamagePayouts(step.incident.damages, policy.items);
196	  policy.remainingCap -= payout;
197	  return { payout, remainingCap: policy.remainingCap };
198	};
199	
200	export const runScenario = (scenario: Scenario): ScenarioResult => {
201	  let quoteCount = 0;
202	  const policies: Policy[] = [];
203	  const results: StepResult[] = scenario.steps.map((step) => {
204	    if (step.op === "claim") return claimStep(step, policies[step.policy]);
205	    const isFollowUp = quoteCount > 0;
206	    quoteCount += 1;
207	    policies.push(createPolicy(step.items));
208	    return quoteStep(step, scenario.customer, isFollowUp);
209	  });
210	  return { results };
211	};
